1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Damage = { itemType: string; amount: number };
10	
11	export type ClaimStep = {
12	  kind: "claim";
13	  policy: number;
14	  incident: { cause?: string; damages: Damage[] };
15	};
16	
17	export type Step = QuoteStep | ClaimStep;
18	
19	export type Customer = { yearsWithMHPCO: number };
20	
21	export type Scenario = {
22	  customer: Customer;
23	  steps: Step[];
24	};
25	
26	export type ScenarioResult = {
27	  results: unknown[];
28	};
29	
30	const COMPONENT_BASE_PREMIUM = 25;
31	
32	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: COMPONENT_BASE_PREMIUM,
38	  moonstone: COMPONENT_BASE_PREMIUM,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_THRESHOLD_YEARS = 2;
45	const PROCESSING_FEE = 5;
46	
47	const CURSED_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	
51	function isCursed(item: Item): boolean {
52	  return item.cursed === true;
53	}
54	
55	function isHighlyEnchanted(item: Item): boolean {
56	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
57	}
58	
59	function riskMultiplierForItem(item: Item): number {
60	  return (
61	    1 +
62	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
63	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
64	  );
65	}
66	
67	function basePremiumForItem(item: Item): number {
68	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
69	}
70	
71	type QuoteResult = { kind: "quote"; premium: number };
72	type ClaimResult = { kind: "claim"; payout: number };
73	type StepResult = QuoteResult | ClaimResult;
74	
75	function claimStep(_step: ClaimStep): ClaimResult {
76	  return { kind: "claim", payout: undefined as unknown as number };
77	}
78	
79	const BUILDING_BLOCK_BASE_PREMIUM = 60;
80	const BUILDING_BLOCK_SIZE = 3;
81	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
82	
83	type ItemGroup = { kind: Item["kind"]; items: Item[] };
84	
85	function groupByKind(items: Item[]): ItemGroup[] {
86	  const groups = new Map<Item["kind"], Item[]>();
87	  for (const item of items) {
88	    const group = groups.get(item.kind) ?? [];
89	    group.push(item);
90	    groups.set(item.kind, group);
91	  }
92	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
93	}
94	
95	function isComponentKind(kind: Item["kind"]): boolean {
96	  return COMPONENT_KINDS.includes(kind);
97	}
98	
99	function isBuildingBlock(group: ItemGroup): boolean {
100	  return group.items.length === BUILDING_BLOCK_SIZE && isComponentKind(group.kind);
101	}
102	
103	function basePremiumForGroup(group: ItemGroup): number {
104	  if (isBuildingBlock(group)) {
105	    return BUILDING_BLOCK_BASE_PREMIUM;
106	  }
107	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
108	}
109	
110	function basePremiumForItems(items: Item[]): number {
111	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
112	}
113	
114	function contractSequenceRate(contractIndex: number): number {
115	  return contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
116	}
117	
118	function loyaltyRate(customer: Customer): number {
119	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
120	}
121	
122	function customerRateForContract(
123	  contractIndex: number,
124	  customer: Customer,
125	): number {
126	  return contractSequenceRate(contractIndex) + loyaltyRate(customer);
127	}
128	
129	function quoteStep(
130	  step: QuoteStep,
131	  contractIndex: number,
132	  customer: Customer,
133	): QuoteResult {
134	  const basePremium = basePremiumForItems(step.items);
135	  const customerAdjustment = basePremium * customerRateForContract(contractIndex, customer);
136	  const premium = Math.ceil(basePremium + customerAdjustment + PROCESSING_FEE);
137	  return { kind: "quote", premium };
138	}
139	
140	function processStep(
141	  step: Step,
142	  contractIndex: number,
143	  customer: Customer,
144	): StepResult {
145	  if (step.kind === "quote") {
146	    return quoteStep(step, contractIndex, customer);
147	  }
148	  return claimStep(step);
149	}
150	
151	export function processScenario(scenario: Scenario): ScenarioResult {
152	  let contractIndex = 0;
153	  const results = scenario.steps.map((step) => {
154	    const result = processStep(step, contractIndex, scenario.customer);
155	    if (step.kind === "quote") contractIndex += 1;
156	    return result;
157	  });
158	  return { results };
159	}
